import axios from "axios";


// ======================================================
// BASE URL
// ======================================================
// Change this if your backend runs on different port

const BASE_URL = "http://localhost:5000/api";


// ======================================================
// CREATE AXIOS INSTANCE
// ======================================================

const API = axios.create({

  baseURL: BASE_URL,

  headers: {

    "Content-Type": "application/json",

  },

});



// ======================================================
// REQUEST INTERCEPTOR
// Attach JWT Token Automatically
// ======================================================

API.interceptors.request.use(

  (config) => {

    const token = localStorage.getItem("token");

    if (token) {

      config.headers.Authorization = `Bearer ${token}`;

    }

    return config;

  },

  (error) => Promise.reject(error)

);



// ======================================================
// RESPONSE INTERCEPTOR
// Handle Token Expire / Unauthorized
// ======================================================

API.interceptors.response.use(

  (response) => response,

  (error) => {

    if (error.response && error.response.status === 401) {

      alert("Session expired. Please login again.");

      localStorage.removeItem("token");

      localStorage.removeItem("user");

      window.location.href = "/login";

    }

    return Promise.reject(error);

  }

);



// ======================================================
// AUTH API
// ======================================================

export const registerUser = async (data) => {

  return await API.post("/auth/register", data);

};



export const loginUser = async (data) => {

  return await API.post("/auth/login", data);

};



// ======================================================
// USER API
// ======================================================

export const getAllUsers = async () => {

  return await API.get("/users");

};



export const getFreelancers = async () => {

  return await API.get("/users/freelancers");

};



export const getClients = async () => {

  return await API.get("/users/clients");

};



// ======================================================
// PROJECT API
// ======================================================

export const createProject = async (data) => {

  return await API.post("/projects", data);

};



export const getAllProjects = async () => {

  return await API.get("/projects");

};



export const getClientProjects = async (clientId) => {

  return await API.get(`/projects/client/${clientId}`);

};



// ======================================================
// PROPOSAL API
// ======================================================

export const sendProposal = async (data) => {

  return await API.post("/proposals", data);

};



export const getProjectProposals = async (projectId) => {

  return await API.get(`/proposals/project/${projectId}`);

};



export const getFreelancerProposals = async (freelancerId) => {

  return await API.get(`/proposals/freelancer/${freelancerId}`);

};



// ======================================================
// ADMIN API
// ======================================================

export const getAdminDashboard = async () => {

  return await API.get("/admin/dashboard");

};



// ======================================================
// DEFAULT EXPORT
// ======================================================

export default API;
